<?php
/** Expense lifecycle and reporting helpers. */
declare(strict_types=1);require_once __DIR__.'/expense_validation.php';function saveExpense(array $in,?int $id=null):array{$e=validateExpenseInput($in);if($e)return[false,$e];$data=['title'=>trim((string)$in['title']),'amount'=>(float)$in['amount'],'expense_type'=>trim((string)($in['expense_type']??'Miscellaneous')),'expense_category_id'=>!empty($in['expense_category_id'])?(int)$in['expense_category_id']:null,'vehicle_id'=>!empty($in['vehicle_id'])?(int)$in['vehicle_id']:null,'trip_id'=>!empty($in['trip_id'])?(int)$in['trip_id']:null,'vendor_name'=>trim((string)($in['vendor_name']??''))?:null,'invoice_number'=>trim((string)($in['invoice_number']??''))?:null,'description'=>trim((string)($in['description']??''))?:null,'remarks'=>trim((string)($in['remarks']??''))?:null,'expense_date'=>$in['expense_date']];if($id){$set=[];foreach($data as $k=>$v)$set[]="$k=?";getDb()->prepare('UPDATE expenses SET '.implode(',',$set).' WHERE id=?')->execute([...array_values($data),$id]);return[true,$id];}$data['uuid']=bin2hex(random_bytes(16));$data['expense_code']='EXP-'.date('Y').'-'.strtoupper(bin2hex(random_bytes(3)));$cols=array_keys($data);getDb()->prepare('INSERT INTO expenses ('.implode(',',$cols).') VALUES ('.implode(',',array_fill(0,count($cols),'?')).')')->execute(array_values($data));$new=(int)getDb()->lastInsertId();logActivity('Expense added','Expense #'.$new);return[true,$new];}
